import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from '../utils/axios';

export default function FindDonors() {
  const { user } = useAuth();
  const [donors, setDonors] = useState([]);
  const [city, setCity] = useState('');
  const [bloodType, setBloodType] = useState('');
  const [loading, setLoading] = useState(false);

  const fetchDonors = () => {
    setLoading(true);
    let url = '/users?role=donor';
    if(city) url += `&city=${encodeURIComponent(city)}`;
    if(bloodType) url += `&blood_type=${encodeURIComponent(bloodType)}`;

    axios.get(url)
      .then(res => setDonors(res.data.filter(d => d.is_available)))
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    // Add real-time debounce or just fetch directly on change
    const timeout = setTimeout(() => {
      fetchDonors();
    }, 300); // 300ms debounce

    return () => clearTimeout(timeout);
  }, [city, bloodType]);

  if (user?.role !== 'patient' && user?.role !== 'admin') return <div style={{ textAlign: 'center', marginTop: '4rem', fontSize: '2rem', color: 'var(--text-muted)' }}>Acc├¿s Refus├®</div>;

