        <input 
          value={city} 
          onChange={e => setCity(e.target.value)} 
          style={{ padding: '0.6rem 1rem', borderRadius: '8px', border: '1px solid var(--gray-200)', minWidth: '150px', flex: '1' }} 
          placeholder="Ville (ex: Casablanca)" 
        />
        <select 
          value={bloodType} 
          onChange={e => setBloodType(e.target.value)} 
          style={{ padding: '0.6rem 1rem', borderRadius: '8px', border: '1px solid var(--gray-200)', minWidth: '150px', flex: '1' }}
        >
          <option value="">Tous les groupes</option>
          <option value="O+">O+</option>
          <option value="O-">O-</option>
          <option value="A+">A+</option>
          <option value="A-">A-</option>
          <option value="B+">B+</option>
          <option value="B-">B-</option>
          <option value="AB+">AB+</option>
          <option value="AB-">AB-</option>
        </select>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1.5rem' }}>
        {loading ? (
             <div style={{ gridColumn: '1 / -1', display: 'flex', justifyContent: 'center', padding: '3rem' }}>
               <div className="loader" style={{ border: '4px solid #f3f3f3', borderTop: '4px solid var(--primary-red)', borderRadius: '50%', width: '40px', height: '40px', animation: 'spin 1s linear infinite' }}></div>
               <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
             </div>
        ) : donors.length > 0 ? donors.map(donor => (
          <div key={donor.id} className="request-card" style={{ padding: '2rem', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
